static enum MHD_Result send_response(struct MHD_Connection *connection,
    const char *body, unsigned int status_code, const char *total_count) {
    struct MHD_Response *response = MHD_create_response_from_buffer(
        strlen(body), (void *)body, MHD_RESPMEM_MUST_COPY);
    MHD_add_response_header(response, "Content-Type", "application/json");
    MHD_add_response_header(response, "Access-Control-Allow-Origin", "*");
    MHD_add_response_header(response, "Access-Control-Allow-Methods", "GET, POST, PUT, DELETE, OPTIONS");
    MHD_add_response_header(response, "Access-Control-Allow-Headers", "Content-Type, X-API-Key");
    if (total_count) {
        MHD_add_response_header(response, "X-Total-Count", total_count);
    }
    enum MHD_Result ret = MHD_queue_response(connection, status_code, response);
    MHD_destroy_response(response);
    return ret;
}

static enum MHD_Result send_json(struct MHD_Connection *connection,
    const char *body, unsigned int status_code) {
    return send_response(connection, body, status_code, NULL);
}

static enum MHD_Result send_options(struct MHD_Connection *connection) {
