}

/* Simple JSON string extraction - finds "key":"value" and returns value (unescaped) */
static char *json_get_string(const char *json, const char *key) {
    char search[256];
    snprintf(search, sizeof(search), "\"%s\"", key);
    const char *p = strstr(json, search);
    if (!p) return NULL;
    p += strlen(search);
    /* skip whitespace and colon */
    while (*p && (isspace((unsigned char)*p) || *p == ':')) p++;
    if (*p == 'n' && strncmp(p, "null", 4) == 0) return NULL;
    if (*p != '"') return NULL;
    p++; /* skip opening quote */

    /* Parse the string value with escape handling */
    size_t cap = 256;
    size_t len = 0;
    char *result = malloc(cap);
    while (*p && *p != '"') {
        if (len + 4 >= cap) {
            cap *= 2;
            result = realloc(result, cap);
        }
        if (*p == '\\') {
            p++;
            switch (*p) {
                case '"': result[len++] = '"'; break;
                case '\\': result[len++] = '\\'; break;
                case '/': result[len++] = '/'; break;
                case 'n': result[len++] = '\n'; break;
                case 'r': result[len++] = '\r'; break;
                case 't': result[len++] = '\t'; break;
                case 'b': result[len++] = '\b'; break;
                case 'f': result[len++] = '\f'; break;
                case 'u': {
                    /* basic \uXXXX - just store as UTF-8 or raw */
                    unsigned int cp = 0;
                    for (int i = 0; i < 4 && p[1]; i++) {
                        p++;
                        cp <<= 4;
                        if (*p >= '0' && *p <= '9') cp |= (*p - '0');
                        else if (*p >= 'a' && *p <= 'f') cp |= (*p - 'a' + 10);
                        else if (*p >= 'A' && *p <= 'F') cp |= (*p - 'A' + 10);
                    }
                    if (cp < 0x80) {
                        result[len++] = (char)cp;
                    } else if (cp < 0x800) {
                        result[len++] = (char)(0xC0 | (cp >> 6));
                        result[len++] = (char)(0x80 | (cp & 0x3F));
                    } else {
                        result[len++] = (char)(0xE0 | (cp >> 12));
                        result[len++] = (char)(0x80 | ((cp >> 6) & 0x3F));
                        result[len++] = (char)(0x80 | (cp & 0x3F));
                    }
                    break;
                }
                default: result[len++] = *p; break;
            }
        } else {
            result[len++] = *p;
        }
        p++;
    }
    result[len] = '\0';
    return result;
}

/* Check if title is present and non-empty (not just whitespace) */
static int title_valid(const char *title) {
    if (!title) return 0;
    /* Check if entirely empty */
    if (title[0] == '\0') return 0;
    return 1;
}

static int parse_id_from_url(const char *url) {
    /* url is like /api/notes/123 */
    const char *p = url + strlen("/api/notes/");
    if (!*p) return -1;
    /* check it's all digits */
    for (const char *c = p; *c; c++) {
        if (!isdigit((unsigned char)*c)) return -1;
    }
    return atoi(p);
}

enum MHD_Result route_request(struct MHD_Connection *connection, const char *url,
                              const char *method, const char *upload_data,
                              size_t *upload_data_size, void **con_cls) {

    /* OPTIONS preflight */
    if (strcmp(method, "OPTIONS") == 0) {
        return send_options(connection);
    }

    /* Handle body accumulation for POST/PUT */
    if (strcmp(method, "POST") == 0 || strcmp(method, "PUT") == 0) {
        if (*con_cls == NULL) {
            struct connection_info *ci = calloc(1, sizeof(struct connection_info));
            ci->data = NULL;
            ci->data_size = 0;
            *con_cls = ci;
            return MHD_YES;
        }
        struct connection_info *ci = *con_cls;
        if (*upload_data_size > 0) {
            /* Check body size limit */
            if (ci->data_size + *upload_data_size > MAX_BODY_SIZE) {
                *upload_data_size = 0;
                return send_json(connection, "{\"error\":\"payload too large\"}", MHD_HTTP_PAYLOAD_TOO_LARGE);
            }
            ci->data = realloc(ci->data, ci->data_size + *upload_data_size + 1);
            memcpy(ci->data + ci->data_size, upload_data, *upload_data_size);
            ci->data_size += *upload_data_size;
            ci->data[ci->data_size] = '\0';
            *upload_data_size = 0;
            return MHD_YES;
        }
        /* upload complete, fall through to processing */
    }

    /* GET /api/notes - list with pagination */
    if (strcmp(url, "/api/notes") == 0 && strcmp(method, "GET") == 0) {
        const char *limit_str = MHD_lookup_connection_value(connection, MHD_GET_ARGUMENT_KIND, "limit");
        const char *offset_str = MHD_lookup_connection_value(connection, MHD_GET_ARGUMENT_KIND, "offset");
        int limit = 50;
        int offset = 0;
        if (limit_str) limit = atoi(limit_str);
        if (offset_str) offset = atoi(offset_str);
        if (limit <= 0) limit = 50;
        if (limit > 100) limit = 100;
        if (offset < 0) offset = 0;

        int total = get_total_notes_count();
        char total_str[32];
        snprintf(total_str, sizeof(total_str), "%d", total);

        char *json = get_notes_paginated_json(limit, offset);
        if (!json) json = strdup("[]");
        enum MHD_Result r = send_response(connection, json, MHD_HTTP_OK, total_str);
        free(json);
        return r;
    }

    /* POST /api/notes - create */
    if (strcmp(url, "/api/notes") == 0 && strcmp(method, "POST") == 0) {
        if (!api_key_valid(connection)) {
            return send_json(connection, "{\"error\":\"unauthorized\"}", MHD_HTTP_UNAUTHORIZED);
        }
        struct connection_info *ci = *con_cls;
        if (!ci || !ci->data || ci->data_size == 0) {
            return send_json(connection, "{\"error\":\"title is required\"}", MHD_HTTP_BAD_REQUEST);
        }
        if (ci->data_size > MAX_BODY_SIZE) {
            return send_json(connection, "{\"error\":\"payload too large\"}", MHD_HTTP_PAYLOAD_TOO_LARGE);
        }
        char *title = json_get_string(ci->data, "title");
        char *content = json_get_string(ci->data, "content");
        if (!title_valid(title)) {
            free(title);
            free(content);
            return send_json(connection, "{\"error\":\"title is required\"}", MHD_HTTP_BAD_REQUEST);
        }
        int id = create_note(title, content ? content : "");
        if (id < 0) {
            free(title);
            free(content);
            return send_json(connection, "{\"error\":\"internal error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
        }
        char *note_json = get_note_json(id);
        if (!note_json) {
            free(title);
            free(content);
            return send_json(connection, "{\"error\":\"internal error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
        }
        enum MHD_Result r = send_json(connection, note_json, MHD_HTTP_CREATED);
        free(note_json);
        free(title);
        free(content);
        return r;
    }

    /* Routes with /api/notes/{id} */
    if (strncmp(url, "/api/notes/", 11) == 0) {
        int id = parse_id_from_url(url);
        if (id < 0) {
            return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
        }

        /* GET /api/notes/{id} */
        if (strcmp(method, "GET") == 0) {
            char *json = get_note_json(id);
            if (!json) {
                return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
            }
            enum MHD_Result r = send_json(connection, json, MHD_HTTP_OK);
            free(json);
            return r;
        }

        /* PUT /api/notes/{id} */
        if (strcmp(method, "PUT") == 0) {
            if (!api_key_valid(connection)) {
                return send_json(connection, "{\"error\":\"unauthorized\"}", MHD_HTTP_UNAUTHORIZED);
            }
            struct connection_info *ci = *con_cls;
            if (!ci || !ci->data || ci->data_size == 0) {
                return send_json(connection, "{\"error\":\"title is required\"}", MHD_HTTP_BAD_REQUEST);
            }
            if (ci->data_size > MAX_BODY_SIZE) {
                return send_json(connection, "{\"error\":\"payload too large\"}", MHD_HTTP_PAYLOAD_TOO_LARGE);
            }
            if (!note_exists(id)) {
                return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
            }
            char *title = json_get_string(ci->data, "title");
            char *content = json_get_string(ci->data, "content");
            if (!title_valid(title)) {
                free(title);
                free(content);
                return send_json(connection, "{\"error\":\"title is required\"}", MHD_HTTP_BAD_REQUEST);
            }
            int rc = update_note(id, title, content ? content : "");
            free(title);
            free(content);
            if (rc != 0) {
                return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
            }
            char *json = get_note_json(id);
            if (!json) {
                return send_json(connection, "{\"error\":\"internal error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
            }
            enum MHD_Result r = send_json(connection, json, MHD_HTTP_OK);
            free(json);
            return r;
        }

        /* DELETE /api/notes/{id} */
        if (strcmp(method, "DELETE") == 0) {
            if (!api_key_valid(connection)) {
                return send_json(connection, "{\"error\":\"unauthorized\"}", MHD_HTTP_UNAUTHORIZED);
            }
            if (!note_exists(id)) {
                return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
            }
            int rc = delete_note(id);
            if (rc != 0) {
                return send_json(connection, "{\"error\":\"internal error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
            }
            return send_json(connection, "{\"status\":\"deleted\"}", MHD_HTTP_OK);
        }
    }

    return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
}
